      // Verify other slices are still present
      expect(state).toHaveProperty('bannerAlert');
      expect(state).toHaveProperty('branding');
      expect(state).toHaveProperty('clusterConfig');
      expect(state).toHaveProperty('devWorkspaces');
      expect(state).toHaveProperty('workspaces');
